head.script:
//==================================================================================================================
// id       : fi_404_01_11b
// 이름     : 사업소득/기타소득등록 (탭)
// 경로     : 재무회계/세무/원천세/
// 사용계정 : 내부
// 파라미터 :
//            IN  :
//            OUT :
//
// 비고     : 
//           1:귀속부서,2:계정,3:거래처,4:사업소득거래처,5:기타소득거래처,6:사업자등록번호,8:근무지,9:차량번호
// 레포트   :
//            /ac/fi/taxbiz/withhold/fi_404_01_11b_02.ozr (사업소득)
//            /ac/fi/taxbiz/withhold/fi_404_01_11b.ozr    (기타소득)
// 업로드   :
// 다운로드 : 
// 호출     :
//            
//==================================================================================================================

// 로그인사용자 정보
scwin.vLoginCoCd     =  "";  // 소속 자회사   
scwin.vLoginCoClsCd  =  "";  // 회계_회사구분('CO035' : 0:동부 EXPRESS)
scwin.vUserHomeClsCd =  "";  // 사용자소속구분코드 
scwin.privAdmin      =  "";  // 어드민권한
scwin.userId         =  "";  // 사용자ID 
scwin.vCoCd          =  "";  // 회사코드
scwin.vCoClsCd       =  "";  // 소속회사종류 : 회계_회사구분('CO035' : 0:동부 EXPRESS)

scwin.vAdminYn       =  "";  // 어드민여부
scwin.userEmpNo      =  "";  // 사용자번호 

scwin.isSubCompany   = false;  // 자회사여부 

scwin.acctDeptCd     =   "";  // 회계부서코드
scwin.acctDeptNm     =   "";  // 회계부서명

scwin.temp_cnt       =    0;  // 행삭제,추가용
scwin.clsCd;
scwin.sChk           =    0;  // 미선택 : 0, 미전표번호 선택 : 1, 전표번호 선택 : 2
scwin.sBizIncome     = "Z2";  // 사업소득
scwin.sEtcIncome     = "Z3";  // 기타소득


scwin.txt_acctDeptCd =   "";
scwin.txt_costClsCd  =   "";  // 비용구분
scwin.txt_acctClsCd  =   "";
scwin.txt_rltSeq     =   "";  // 관련사건저장순번 - 문자

// <INPUT type="hidden" class=input_text id=txt_eqCd objType="data"  name="txt_eqCd">
scwin.txt_eqCd       =   "";   // 장비코드
// <INPUT type="hidden" class=input_text id=txt_evidClsNm objType="data"  name="txt_evidClsNm">
scwin.txt_evidClsNm  =   "";   // 공제종류명

// <input type="hidden" name ="txtCoClsCd" id ="txtCoClsCd">
// <input type="hidden" name ="txtCrn" id ="txtCrn">
// <input type="hidden" name ="txtClntCrn" id ="txtClntCrn">
scwin.txtCoClsCd     =   "";  // 회사구분
scwin.txtCrn         =   "";
scwin.txtClntCrn     =   "";  // 사업자등록자번호 (팝업)

scwin.ed_coCd_hidVal            = "";  // 회사 히든값
scwin.ed_declarDept_hidVal      = "";  // 귀속부서 (1)
scwin.ed_acctCd_hidVal          = "";  // 계정     (2)
scwin.ed_clntNo_hidVal          = "";  // 거래처   (3)
scwin.ed_bizIncomeClntNo_hidVal = "";  // 사업소득거래처 (4)
scwin.ed_etcIncomeClntNo_hidVal = "";  // 기타소득거래처 (5)
scwin.ed_workSiteCd_hidVal      = "";  // 근무지 (8)
scwin.ed_vehclShortCd_hidVal    = "";  // 차량번호 (9)

scwin.isStarted             = true;  // 최초 이벤트 여부 (자회사 구분 로직을 최초 한번만 실행-팝업 리턴 시간차)

scwin.rowChangeOk           = true;  // row 변경 가능 여부 - 최초 조회시 1번 row 대응


scwin.onpageload = function() {

    console.log("====== onpageload ================== v. 1.03");

    // 회원정보를 json 데이터로 모두 받음
    let memJson = $c.data.getMemInfo();

    // 로그인 정보 추출
    let coCd    = $c.gus.cfIsNull( $c.data.getMemInfo("coCd") ) ? '' : $c.data.getMemInfo("coCd");
    let coClsCd = $c.gus.cfIsNull( $c.data.getMemInfo("coClsCd") ) ? '' : $c.data.getMemInfo("coClsCd");
    let userHomeClsCd = $c.data.getMemInfo("userHomeClsCd");  // 사용자소속구분코드
    let userId     = $c.data.getMemInfo("userId");
    let privAdmin  = $c.data.getMemInfo("privAdmin");
    let empNo      = $c.data.getMemInfo("empNo");

    scwin.vLoginCoCd     = coCd;
    scwin.vLoginCoClsCd  = coClsCd;
    scwin.vUserHomeClsCd = userHomeClsCd;

    scwin.vCoCd          = coCd;      
    scwin.vCoClsCd       = coClsCd;   
    scwin.userId         = userId;
    scwin.vAdminYn       = privAdmin;
    scwin.userEmpNo      = empNo;

    console.log("▶▶ vLoginCoCd : "+ scwin.vLoginCoCd +"   loginCoClsCd : "+ scwin.vLoginCoClsCd );
    console.log("▶▶ vCoCd      : "+ scwin.vCoCd +"   vCoClsCd : "+ scwin.vCoClsCd );
    console.log("▶▶ userId     : "+ scwin.userId +"   userEmpNo : "+ scwin.userEmpNo);
    console.log("▶▶ vUserHomeClsCd : "+ scwin.vUserHomeClsCd +"   vAdminYn : "+ scwin.vAdminYn);
//    console.log("▶▶ memJson : "+ JSON.stringify(memJson));

    // 회계부서코드/명
    let acctDeptCd = $c.data.getMemInfo("acctDeptCd");
    let acctDeptNm = $c.data.getMemInfo("acctDeptNm");

    scwin.acctDeptCd = acctDeptCd;
    scwin.acctDeptNm = acctDeptNm;

    console.log("▶▶ acctDeptCd : "+ scwin.acctDeptCd +"   acctDeptNm : "+ scwin.acctDeptNm);

    // 공통코드 : onPageLoad 에 위치
    const codeOptions = [
        //  { grpCd : "FI053", compID : "lc_withholdClsCd" }  // 원천세구분코드
         { grpCd : "FI053", compID : "lc_withholdClsCd", opt:{"range" : "1,A"} }  // 원천세구분코드
        ,{ grpCd : "FI086", compID : "lc_localAlienClsCd" }  // 내외국인구분
        ,{ grpCd : "FI084", compID : "lc_businessClsCd" }    // 업종구분코드
        ,{ grpCd : "FI085", compID : "lc_incomeClsCd" }      // 소득구분코드
        ,{ grpCd : "FI073", compID : "lc_reqPayMthdCd" }     // 지급수단
        ,{ grpCd : "FI005", compID : "lc_deductClsCd" }      // 공제종류코드  
    ];
    console.log(" codeOptions : "+ JSON.stringify(codeOptions));
    $c.data.setCommonCode(codeOptions);
};


//-------------------------------------------------------------------------
// 공통코드 후처리
//-------------------------------------------------------------------------
scwin.ondataload = function(e) {
    console.log("=== ondataload (공통코드2중화 - 복사후 필터)");

     let dltStr = "dlt_commonCodeFI053"; // 코드의 dataList
     let dlt = $c.gus.object(dltStr);
     $c.gus.copy(dltStr, "dlt_commonCodeFI053_1", true); // dlt_commonCodeFI053_1 으로 dataList 을 복사

     let dlt2 = $c.gus.object("dlt_commonCodeFI053_1"); // 객체화
    //  $c.data.dataListFilter(dlt2, "fltrCd1 == 'A'");  // 새로운 데이터리스트에 필터("range" : "1,A")
};

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    console.log("==-==-== onUdcCompleted");

    $p.setTimeout(function() {

	    scwin.f_Header();
	    $c.gus.cfDisableKeyData();

        // KYU_NEW : 버튼 비활성
        $c.gus.cfDisableObjects([btn_acctCd,btn_clntNo,btn_bizIncomeClntNo,btn_etcIncomeClntNo,btn_workSiteCd,btn_vehclShortCd ]);

	    // $c.gus.cfDisableBtnOnly([btUpdate]);
        $c.gus.cfDisableBtnOnly([btn_btUpdate]);
	    $c.gus.cfEnableObjects([btn_clntNo,btn_acctCd]);

	    // cfSetIMEModeActiveObjects([txt_summary]);

        scwin.f_setCompanyInfo();

        //증빙종류 조회
        scwin.getEvidInfo();

        cbx_printCheck.checkAll(true);
        cbx_previewCheck.checkAll(true);
// debugger;
    }, {"delay":50});
};

//-------------------------------------------------------------------------
// function name : f_setInitObj
// function desc : 귀속부서에 따라 Object Init
// function Parameter : null 
//-------------------------------------------------------------------------
scwin.f_setInitObj = function()
{  
	$c.gus.cfInitObjects([ed_clntNo,ed_clntNm ]); 						//거래처 

	if(scwin.txtCoClsCd > ACConstants.CO_CLS_CD_DONGBU ) {  	// 자회사 회계 시스템  
        console.log("  -- 원천세구분코드 FI053 변경 (1,D)");

		// lc_withholdClsCd.CBData="<%=GauceUtil.getCodeList("FI053",1,"A")%>" ;
	} else {
        console.log("  -- 원천세구분코드 FI053 변경 (1,D) index 0");

	    // lc_withholdClsCd.CBData="<%=GauceUtil.getCodeList("FI053",1,"A")%>" ;
	    lc_withholdClsCd.index =0; 		    
	}
};



// @@ ====== 준비 ============================================================================== //

//-------------------------------------------------------------------------
// function name : f_Header
// function desc : 헤더생성
// function Parameter : null
//-------------------------------------------------------------------------
scwin.f_Header = function()
{
    // 원천세내역헤더생성
    // ds_search.UseChangeInfo = false;
    ds_search.set("flag", "1");
    ds_search.set("coClsCd", scwin.txtCoClsCd);

    // KYU_TEST : 주석 처리. 초기 조회는 의미없음
	// tr_search.post();
    // $c.sbm.execute(sbm_search);

    var thisYm = $c.date.getServerDateTime("yyyyMM");

    ds_search.set("closeYm", thisYm);
    // Session 이용
    ds_search.set("declarDept"   , scwin.acctDeptCd );
    ds_search.set("declarDeptNm" , scwin.acctDeptNm );
    scwin.ed_declarDept_hidVal   = scwin.acctDeptCd;

    // KYU_NEW : 강제로 팝업. 초기 onChange 이벤트 scwin.clsCd  --> 계정의 전체 건수
    scwin.f_openPopUp('1','T');
};

//-------------------------------------------------------------------------
// 자회사 회계 시스템 추가에 따른 설정
//-------------------------------------------------------------------------
scwin.f_setCompanyInfo = function()
{
 	 // 사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를  '동부 EXPRESS'로  Default set
 	if( scwin.vUserHomeClsCd != ACConstants.SUBSIDIARY_USER_HOME_CLS_CD )  {
 		scwin.vCoCd = ACConstants.CO_CD_DONGBU ;
 		scwin.vCoClsCd =  ACConstants.CO_CLS_CD_DONGBU ;
	}

	ed_coCd.setValue( scwin.vCoCd );

	scwin.f_PopUpCompanyInfo('T');  // 속도 지연 문제

    // KYU_ORDER : 회사팝업 콜백으로 이동 (팝업 리턴 시간차)
	// if('T' == '<%=privAdmin%>'  ||  !isSubCompany   ) { // ADMIN 권한이 있는 경우, 동부 EXPRESS 인 경우
	// 	cfEnableObjects([ed_coCd,txt_coNm,img_company ]);
    //   }else {
    // 	cfDisableObjects([ed_coCd,txt_coNm,img_company  ]);
    // }
};

//-------------------------------------------------------------------------
// 증빙종류 조회
//-------------------------------------------------------------------------
scwin.getEvidInfo = async function() {
	//증빙종류 조회
	    // ds_evidClsCd.DataId = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC"
		// 							+ "&queryId=retrieveEvidInfo&param3=PCHS";
	    // ds_evidClsCd.Reset();

    ds_commonCode.setEmptyValue() ;
	const strParam = {
                  sysCd              : "CommonEBC"           // 시스템코드
                , queryId            : "retrieveEvidInfo"    // 쿼리ID
                , param1             : ""
                , param2             : ""
                , param3             : "PCHS"                // CD
            };

    //데이터셋에 정보설정
    ds_commonCode.setJSON(strParam);
    await $c.sbm.execute(sbm_evidClsCd);
};

//-------------------------------------------------------------------------
// 증빙종류조회 submitdone
//-------------------------------------------------------------------------
scwin.sbm_evidClsCd_submitdone = function (e) {
    console.log("▷ sbm_evidClsCd_submitdone (증빙종류조회)");

    if( e.responseJSON.resultDataSet[0].Code != 0 ) return;

    if(e.responseJSON.GAUCE) {
        ds_evidClsCd.setJSON(e.responseJSON.GAUCE);
    }
};


// @@ ====== 조회 ============================================================================== //

//-------------------------------------------------------------------------
// function name : f_Retrieve
// function desc : 사업소득/기타소득 조회
// function Parameter : null
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function()
{
    console.log("====== f_Retrieve ==================");

	// if (!cfValidate([ed_closeYm,ed_declarDept])) {
    let ret1 = await $c.gus.cfValidate([ica_closeYm,ed_declarDept]);
    if ( !ret1 )
	   return false;

	// if (!cfValidate([ed_coCd]))
    let ret2 = await $c.gus.cfValidate([ed_coCd]);
    if ( !ret2 )
  		return false;

  	var chkCocd = ed_coCd.getValue();

	// ds_search.UseChangeInfo = false;
	ds_search.set("flag", "");

// <C> Col=coClsCd		         	Ctrl=txtCoClsCd                 Param=value   </C>
    ds_search.set("coClsCd", scwin.txtCoClsCd);

    var dcJSON = ds_search.getJSON();
    console.log("  *** ds_search : "+ JSON.stringify(dcJSON));

	// tr_search.post();
    $c.sbm.execute(sbm_search);
};

//-------------------------------------------------------------------------
// 조회(사업소득/기타소득 조회) submitdone
//-------------------------------------------------------------------------
scwin.sbm_search_submitdone = function (e) {
    console.log("▷▷ sbm_search_submitdone");

    var chkCocd = ed_coCd.getValue();

    if( e.responseJSON.resultDataSet[0].Code != 0 ) return;

// language=JavaScript for=ds_withhold event=OnLoadCompleted(rowCnt)>
//     cfHideDSWaitMsg(gr_withhold);
//     cfShowTotalRows(totalRows, rowCnt);
    var rowCnt = ds_withhold.getTotalRow();
    ed_totalRows.setValue(rowCnt);

    scwin.temp_cnt = rowCnt;
    if( rowCnt == 0 ){
    	//cfAlertMsg(MSG_CM_WRN_002);
    }else{
    	$c.gus.cfEnableAllBtn();
    }
	scwin.sChk = 0;  // 미선택 : 0, 미전표번호 선택 : 1, 전표번호 선택 : 2

    // gr_withhold.ColumnProp('checkYn','HeadCheck')="false";
    gr_withhold.setHeaderValue("checkYn", false);  // 헤더 체크 풀기

	// if('T' == scwin.vAdminYn  ||  !scwin.isSubCompany   ) { // ADMIN 권한이 있는 경우, 동부 EXPRESS 인 경우
	//     $c.gus.cfEnableObjects([ed_coCd,ed_coNm,btn_coCd ]);
	// }else {
	//     $c.gus.cfDisableObjects([ed_coCd,ed_coNm,btn_coCd ]);
	// }

    // KYU_TEST
    // s_withhold 의 onRowPosition 발동
    scwin.f_canRowPosChange(0, 0);

    // KYU_TEST : 왜 하는 건지
    ed_coCd.setValue( chkCocd );

    // KYU_TEST : 전표번호 있는 row 의 체크박스 비활성화
    // scwin.readOnlyCheckYn();

    // 그리드 포커스
    gr_withhold.setFocusedCell(0, "payDt", false);
};


// @@ ====== 그리드 / DS - 기타 ================================================================ //

//-------------------------------------------------------------------------
// 전표내역팝업 로딩
//-------------------------------------------------------------------------
scwin.gr_withhold_oncellclick = function (rowIndex, columnIndex, columnId) {
    var Row = rowIndex;
    var Colid = columnId;
// <!-- 전표번호 클릭시  -->
// language="javascript"  for=gr_withhold event=OnClick(Row,Colid)>
	if(Colid=="slipNo" && ds_withhold.getCellData(Row,"slipNo")!=""){
	    $c.gus.cfShowSlipInfo(ds_withhold.getCellData(Row,"slipNo"));
	}

    // 역분개전표번호
	if(Colid=="reverseSlipNo" && ds_withhold.getCellData(Row,"reverseSlipNo")!=""){
		cfShowSlipInfo(ds_withhold.getCellData(Row,"reverseSlipNo"));
	}
};

//-------------------------------------------------------------------------
// readOnlyCheckYn  (KYU_TEST)
//-------------------------------------------------------------------------
scwin.readOnlyCheckYn = function () {
    console.log("=== readOnlyCheckYn (전표번호 있는 row 의 체크박스 비활성화)");

	for ( i = 0 ; i < ds_withhold.getTotalRow() ; i++){

		if( gr_withhold.getCellData(i,"slipNo")=="" ){
            gr_withhold.setCellReadOnly(i, "checkYn", false);
		} else {
            gr_withhold.setCellReadOnly(i, "checkYn", true);
        }
	}
};

//-------------------------------------------------------------------------
// 전표번호에 따른 체크박스 비활성화 : 전표번호에 지정됨 (삭제)
//-------------------------------------------------------------------------
scwin.slipNoExp = function(data, formatData, rowIndex, colIndex) {
    // console.log("   data ["+data+"] rowIndex ["+rowIndex+"]");
    if(data == "") {
        gr_withhold.setCellReadOnly(rowIndex, "checkYn", false);
    } else {
        gr_withhold.setCellReadOnly(rowIndex, "checkYn", true);
    }
    return data;
};

//-------------------------------------------------------------------------
// 작성일자 변경시 : ds_withhold 지급일자 동기화
//-------------------------------------------------------------------------
scwin.ica_slipDt_onchange = function () {
    // <C> Col=payDt                     	Ctrl=ed_slipDt                    Param=text         </C>
    // <C> Col=slipDt                    	Ctrl=ed_slipDt                    Param=text         </C>

    ds_withhold.setCellData(ds_withhold.getRowPosition(), "payDt", ica_slipDt.getValue());
};


//-------------------------------------------------------------------------
// 전체 체크박스 체크
//-------------------------------------------------------------------------
scwin.gr_withhold_onheaderclick = function (headerId) {
    console.log("----- gr_withhold_onheaderclick (전체 체크박스 클릭)");

    var Colid = headerId;
// <!-- 전체체크박스체크시 -->
// language="javascript"  for=gr_withhold event=OnHeadCheckClick(Col,Colid,bCheck)>
	var i = 0;
	if ( Colid == "checkYn"){
        var bCheck = gr_withhold.getHeaderValue("checkYn");  // 체크 여부
        console.log("     헤더 bCheck (체크여부) ["+bCheck+"]");

		// if ( bCheck == "1"){
        if ( bCheck ){  // 체크 되었을 때
			for ( i = 0 ; i < ds_withhold.getTotalRow() ; i++){
                if($c.gus.cfIsNull(ds_withhold.getCellData(i,"slipNo")) || (!$c.gus.cfIsNull(ds_withhold.getCellData(i,"slipNo")) &&
                  !$c.gus.cfIsNull(ds_withhold.getCellData(i,"reverseSlipNo"))) ){
                    console.log("  ---전표번호 ["+i+"]["+ds_withhold.getCellData(i,"slipNo")+"]");

					ds_withhold.setCellData(i,"checkYn", "T");
				}
                // else {
                //     ds_withhold.setCellData(i,"checkYn", "F");  // KYU_TEST : 반대 케이스 넣어야 함
                // }
			}
		} else {
			for ( i = 0 ; i < ds_withhold.getTotalRow() ; i++){
                console.log("  false 전표번호 ["+i+"]["+ds_withhold.getCellData(i,"slipNo")+"]");

				ds_withhold.setCellData(i,"checkYn", "F");
			}
		}
	}
};

//-------------------------------------------------------------------------
// 기타소득/사업소득 그리드 값 변경 시
//-------------------------------------------------------------------------
scwin.gr_withhold_onviewchange = async function (info) {
    console.log("----- gr_withhold_onviewchange (기타소득/사업소득 그리드 값 변경 시)  =========");

// <!-- 기타소득/사업소득 그리드 값 변경 시  -->
// language="javascript"  for=ds_withhold event=OnColumnChanged(Row,Colid)>
    var Row     = info.rowIndex;
    var colidx  = info.colIndex;
    var Colid   = info.colId;
    var olddata = info.oldValue;
    console.log("  Row ["+Row+"]   Colid ["+colidx+" - "+Colid+"]  value(olddata) ["+olddata+"]");

	// 필요경비여부 / 기타소득구분코드 변경 시
	if (Colid == "needEpenseYn" || Colid == "incomeClsCd")
    {
		if (lc_withholdClsCd.getValue() == scwin.sEtcIncome)
        {
            console.log("    -- 기타소득금액이 50,000원 이하이면 기타소득세 및 지방소득세를 납부하지 아니함.");

        	// 기타소득금액이 50,000원 이하이면 기타소득세 및 지방소득세를 납부하지 아니함.
			if (ds_withhold.getCellData(Row, "totSal") != "0" && parseInt(ds_withhold.getCellData(Row, "totSal")) > 50000) {
				if (ds_withhold.getCellData(Row, "needEpenseYn") == "1") {
					var temp1 = (parseInt(ed_totSal.getValue().trim()) - (parseInt(ed_totSal.getValue.trim()) * 0.6)) * scwin.f_ectTaxRate(cbx_needEpenseYn.checked);
                    ed_etcIncomeTax.setValue(temp1);
				} else {
			        var temp2 = parseInt(ed_totSal.getValue().trim()) * scwin.f_ectTaxRate(cbx_needEpenseYn.checked);
                    ed_etcIncomeTax.setValue(temp2);
			    }
				ed_etcManTax.setValue( parseInt(ed_etcIncomeTax.getValue().trim()) * 0.1 );
				ed_etcIncomeTax.setValue( parseInt(ed_etcIncomeTax.getValue()*0.1)*10 );
		    	ed_etcManTax.setValue(  parseInt(ed_etcManTax.getValue()*0.1)*10 );
		    } else {
		    	ed_etcIncomeTax.setValue( parseInt(ed_etcIncomeTax.getValue()*0.1)*10 );
		    	ed_etcManTax.setValue(  parseInt(ed_etcManTax.getValue()*0.1)*10 );
		    }
		}
	}

	// 사업소득구분코드 변경 시
	if (Colid == "businessClsCd") {

        if (lc_withholdClsCd.getValue() == scwin.sBizIncome) {
			if (ds_withhold.getValue(Row, "ed_totSal") != "0") {

		        var temp3 = parseInt(ed_totSal.getValue().trim()) * scwin.f_bizTaxRate();
                ed_bizIncomeTax.setValue( temp3 );

		        var temp4 = parseInt(ed_bizIncomeTax.getValue().trim()) * 0.1;
                ed_bizManTax.setValue( temp4 );
		    }
		}
	}

	// 전표생성과 미전표생성건을 같이 선택 못하도록 체크
	// var nRow = ds_withhold.NameValueRow("checkYn", "T");	// 체크박스 선택인 것을 찾음
    var nRow = ds_withhold.getMatchedJSON("checkYn", "T", true);	// 체크박스 선택인 것을 찾음

    // console.log("  -- -- nRow " + JSON.stringify(nRow));

	var Chk = scwin.sChk;

	if (Colid == "checkYn") {
		if (nRow <= 0) {
			scwin.sChk = 0;	//미선택
		} else {
			if ($c.gus.cfIsNull(ds_withhold.getCellData(Row, "slipNo")) || (ds_withhold.getCellData(Row, "slipNo") != "" && ds_withhold.getCellData(Row, "reverseSlipNo") != "")) {
				scwin.sChk = 1;	// 미전표번호 선택
			} else {
				scwin.sChk = 2;	// 전표번호 선택
			}
		}

		if (Chk == 0) {
//			return;
		} else {
			if (Chk == 1) {
				if (scwin.sChk == 2) {  // 미선택 : 0, 미전표번호 선택 : 1, 전표번호 선택 : 2
					await $c.win.alert("전표번호 미생성된 내역과 생성된 내역은 함께 선택불가합니다.");

				    for (i=0; i< ds_withhold.getTotalRow();i++) {
				    	if (ds_withhold.getCellData(i, "slipNo") == ds_withhold.getCellData(Row, "slipNo")) {
				    		ds_withhold.setCellData(i, "checkYn", "F");
				    	}
				    }
				    scwin.sChk = 1;
					return;
				}
			} else if (Chk == 2) {
				if (scwin.sChk == 1) {  // 미선택 : 0, 미전표번호 선택 : 1, 전표번호 선택 : 2
					await $c.win.alert("전표번호 미생성된 내역과 생성된 내역은 함께 선택불가합니다.");
					ds_withhold.setCellData(Row, "checkYn", "F");
				    scwin.sChk = 2;
					return;
				}
			} else {
				return;
			}
		}
	}
};



//-------------------------------------------------------------------------
// function name : f_Validation
// function desc : 체크
// function Parameter : null
//-------------------------------------------------------------------------
scwin.f_Validation = async function()
{
    console.log("=== f_Validation  ▷▷▷▷");

    // if (!cfValidate([lc_withholdClsCd,ed_slipDt,ed_acctCd,ed_clntNo,ed_taxDt,txt_totStaff,ed_totSal,txt_name,txt_ssn,lc_localAlienClsCd,txt_addr,lc_reqPayMthdCd,lc_evidClsCd,txt_summary]))
    let ret1 = await $c.gus.cfValidate([lc_withholdClsCd,ica_slipDt,ed_acctCd,ed_clntNo,ica_taxDt,ed_totStaff,ed_totSal,ed_name,ed_ssn,lc_localAlienClsCd,ed_addr,lc_reqPayMthdCd,lc_evidClsCd,ed_summary]);
    if ( !ret1 ) {
        console.log("  ------------------ cfValidate error!");
        return false;
    }

	// 사업소득
    if(lc_withholdClsCd.getValue() == scwin.sBizIncome) {
        // if (!cfValidate([ed_bizIncomeClntNo, lc_businessClsCd]))
        let ret2 = await $c.gus.cfValidate([ed_bizIncomeClntNo, lc_businessClsCd]);  // 예수금거래처
        if ( !ret2 )
    	   return false;
    	// 업종구분코드 851101(병의원) 일경우 사업자등록번호 필수
		if (lc_businessClsCd.getValue() == "851101") {
	        // if (!cfValidate([txt_bizIncomeCrn]))
	        let ret3 = $c.gus.cfValidate([ed_bizIncomeCrn]);
            if ( !ret3 )
	    	   return false;
		}
    // 기타소득
    } else if(lc_withholdClsCd.getValue() == scwin.sEtcIncome) {
        // if (!cfValidate([ed_etcIncomeClntNo, lc_incomeClsCd]))
        let ret4 = await $c.gus.cfValidate([ed_etcIncomeClntNo, lc_incomeClsCd]);
        if ( !ret4 )
    	    return false;
    }

    // KYU_ISSUE : 포커스 먼저 이동에 따른 로직 제거
    // KYU_TEST : 이미 포커스 이동했으므로 무의미 - 위의 계정과 아래 계정히든 비교하므로 오류 발생
	// if(!scwin.f_HiddenCheck(ed_acctCd,"계정")) return false;
	// if(!scwin.f_HiddenCheck(ed_clntNo,"거래처")) return false;

	// let ret5 = await scwin.f_HiddenCheck(ed_acctCd,"계정");
    // if ( !ret5 ) return false;
	// let ret6 = await scwin.f_HiddenCheck(ed_clntNo,"거래처");
    // if ( !ret6 ) return false;

    return true;
};


