// function name : f_AddRow
// function desc : 행추가
// function Parameter : null
//-------------------------------------------------------------------------
scwin.f_AddRow = async function() {
    console.log("=== f_AddRow (행추가) ▶▶▶▶");

    // KYU_NEW : 그리드 row 변경시 필수항목 체크
    let rtn0 = await scwin.f_canRowPosChange();
    if (!rtn0)  return;

	// if (!cfValidate([ed_closeYm,ed_declarDept])) return;
    let rtn1  = await $c.gus.cfValidate([ica_closeYm,ed_declarDept]);
    if (!rtn1) return;

    // KYU_ISSUE : 포커스 먼저 이동에 따른 로직 제거
    // if(!f_HiddenCheck(ed_declarDept,"귀속부서")) return;
    // let rtn2 = await scwin.f_HiddenCheck(ed_declarDept,"귀속부서");
    // if ( !rtn2 ) return ;


    var curRow = ds_withhold.getTotalRow()-1;
    if ( curRow < 0 ) {
        curRow = 0;
    }

    // ds_withhold.AddRow();
    if (ds_withhold.getTotalRow() <= 0){
        ds_withhold.insertRow();
        ds_withhold.setRowPosition(0);
        gr_withhold.setFocusedCell(0, "payDt", true);
    }else{
        ds_withhold.insertRow();

        // KYU_TEST : 행추가시 위치
        ds_withhold.setRowPosition( ds_withhold.getTotalRow()-1) ;
        gr_withhold.setFocusedCell(ds_withhold.getRowPosition(), "payDt", false);
    }

    $c.gus.cfEnableObjects([btn_clntNo,btn_acctCd]);
    console.log("  ==--== 활성 (거래처버튼,계정버튼)");

    // KYU_NEW
    $c.gus.cfEnableObjects([btn_workSiteCd,btn_vehclShortCd]);
    console.log("  NEW ==--== 활성 (근무지버튼,차량번호버튼)");

    $c.gus.cfEnableKeyData();
    console.log("  <<<< cfEnableKeyData");

    // cfEnableBtnOnly([bSave]);
    $c.gus.cfEnableBtnOnly([ $c.gus.getctrlBtn('bSave') ]);
    $c.gus.cfDisableObjects([ed_clntNm,ed_acctNm,ed_bizIncomeClntNm,ed_etcIncomeClntNm]);
    ica_slipDt.focus();

    // KYU_TEST : 이해가 안가는 코딩 : 둘 다 동일함
    if( scwin.txtCoClsCd > ACConstants.CO_CLS_CD_DONGBU )  {  	// 자회사 회계 시스템
        console.log("  ==--== 비활성 ( 원천세구분코드 )");
        // lc_withholdClsCd.Enable = true;
	    lc_withholdClsCd.setDisabled( false );
    }else{
        console.log("  ==--== 활성 ( 원천세구분코드 )");
        // lc_withholdClsCd.Enable = true;
        lc_withholdClsCd.setDisabled( false );
    }

    lc_withholdClsCd.setSelectedIndex(0);

    $c.gus.cfEnableObj(ed_bizIncomeTax, false);
    $c.gus.cfEnableObj(ed_bizManTax, false);
    $c.gus.cfEnableObj(ed_etcIncomeTax, false);
    $c.gus.cfEnableObj(ed_etcManTax, false);

	lc_localAlienClsCd.setSelectedIndex(0);

    scwin.f_bizEtcGubun();	// 원천세구분코드

    //lc_evidClsCd.index=0;

    // KYU_NEW : 히든 세팅
    scwin.f_setHidVal();
};

