            ed_clntNm.setValue ( rtnList[1] );     // 명
            scwin.ed_clntNo_hidVal = rtnList[0];  // 히든값
	 		scwin.txtCrn           = rtnList[4];  // 사업자등록번호

            // KYU_NEW : 바인딩 처리
            ds_withhold.setCellData(ds_withhold.getRowPosition(), "crn", scwin.txtCrn);

	 		scwin.txtClntCrn       = rtnList[4];  // 사업자등록번호

        } else {
            ed_clntNo.setValue( "" );     // 코드
            ed_clntNm.setValue ( "" );     // 명
            scwin.ed_clntNo_hidVal = "";  // 히든값
	 		scwin.txtCrn           = "";  // 사업자등록번호

            // KYU_NEW : 바인딩 처리
            ds_withhold.setCellData(ds_withhold.getRowPosition(), "crn", scwin.txtCrn);

	 		scwin.txtClntCrn       = "";  // 사업자등록번호
        }

        console.log(" --==-- txtCrn ["+scwin.txtCrn+"]  txtClntCrn ["+scwin.txtClntCrn+"]");

		// 사업소득
		if(lc_withholdClsCd.getValue() == scwin.sBizIncome) {  // "Z2"	// 사업소득
			if (ed_etcIncomeClntNo.getValue() == "") {
				ed_bizIncomeClntNo.setValue( ed_clntNo.getValue() );
