			}
		// 기타소득
		} else if(lc_withholdClsCd.getValue() == scwin.sEtcIncome) {  // "Z3" 기타소득
			if (ed_bizIncomeClntNo.getValue() == "") {
				ed_etcIncomeClntNo.setValue( ed_clntNo.getValue() );
				ed_etcIncomeClntNm.setValue( ed_clntNm.getValue() );
				scwin.ed_etcIncomeClntNo_hidVal = ed_clntNo.getValue();
				scwin.f_openPopUp('6','T');	// 대표자, 주소 조회
			}
		}
};

