//-------------------------------------------------------------------------
// function name : f_resultPopEd
// function desc : 팝업결과
// function Parameter : strCd : 코드, strNm : 코드명, rtnList : 결과
//  flag : 신규 추가. 어떤 팝업을 호출했는지 구분
//-------------------------------------------------------------------------
scwin.f_resultPopEd = function(strCd,strNm,rtnList, flag){
    console.log("=== f_resultPopEd (팝업결과)   flag ["+flag+"]  1:귀속부서,2:계정,3:거래처,4:사업소득거래처,5:기타소득거래처,6:사업자등록번호,8:근무지,9:차량번호)");

    // if (rtnList != null ) {
    //     if (rtnList[0] == "N/A") {
    //     	return;
    //     }
    //     strCd.Text = rtnList[0];	// 코드
    //     strNm.value = rtnList[1];	// 명
    //     strCd.hidVal = rtnList[0];  // 히든값
    // } else {
    // 	strCd.Text = "";
    // 	strNm.value = "";
    // 	strCd.hidVal = "";
    // }

    if (rtnList != null ) {
        if (rtnList[0] == "N/A") {  // 팝업 그냥 닫음
            // 히든값 분기처리
            switch (flag){
                case '3'  : scwin.ed_clntNo_hidVal          = ""; break;  // 거래처
                case '4'  : scwin.ed_bizIncomeClntNo_hidVal = ""; break;  // 사업소득거래처
                case '5'  : scwin.ed_etcIncomeClntNo_hidVal = ""; break;  // 기타소득거래처
                case '8'  : scwin.ed_workSiteCd_hidVal      = ""; break;  // 근무지
                default   : break;
            }
            return;
        }

        strCd.setValue(rtnList[0]);    // 코드
        strNm.setValue(rtnList[1]);    // 명

        // 히든값 분기처리
        switch (flag){
            case '3'  : scwin.ed_clntNo_hidVal          = rtnList[0]; break;  // 거래처
            case '4'  : scwin.ed_bizIncomeClntNo_hidVal = rtnList[0]; break;  // 사업소득거래처
            case '5'  : scwin.ed_etcIncomeClntNo_hidVal = rtnList[0]; break;  // 기타소득거래처
            case '8'  : scwin.ed_workSiteCd_hidVal      = rtnList[0]; break;  // 근무지
            default   : break;
        }
    }else{
	    strCd.setValue( "" );
		strNm.setValue( "" );

        // 히든값 분기처리
        switch (flag){
            case '3'  : scwin.ed_clntNo_hidVal          = ""; break;  // 거래처
            case '4'  : scwin.ed_bizIncomeClntNo_hidVal = ""; break;  // 사업소득거래처
            case '5'  : scwin.ed_etcIncomeClntNo_hidVal = ""; break;  // 기타소득거래처
            case '8'  : scwin.ed_workSiteCd_hidVal      = ""; break;  // 근무지
            default   : break;
        }
    }
};

//-------------------------------------------------------------------------
// 팝업체크 - 코드값 변경시 자동검색 @@
//   flag : 팝업 플래그
//   KYU_TEST : 6번은 히든이 없으므로 무시
//-------------------------------------------------------------------------
//   1:귀속부서,2:계정,3:거래처,4:사업소득거래처,5:기타소득거래처,6:사업자등록번호,8:근무지,9:차량번호
scwin.f_checkPopEd = function(strCd,strNm,flag) {
    console.log("===== f_checkPopEd (팝업체크 srtCd["+strCd.getValue()+"] strNm["+strNm.getValue()+"] flag["+flag+"]");

	// if (strCd.text.trim() == strCd.hidVal) return;
	//     strNm.value="";
	//     strCd.hidVal="";
	// if(strCd.text.trim()!="") f_openPopUp(flag,'T');

	    // if (strCd.getValue().trim() == strCd.hidVal) return; //return;
	    if ( ( flag=='1'  && (strCd.getValue().trim() == scwin.ed_declarDept_hidVal       )) ||  // 귀속부서
             ( flag=='2'  && (strCd.getValue().trim() == scwin.ed_acctCd_hidVal           )) ||  // 계정
             ( flag=='3'  && (strCd.getValue().trim() == scwin.ed_clntNo_hidVal           )) ||  // 거래처
             ( flag=='4'  && (strCd.getValue().trim() == scwin.ed_bizIncomeClntNo_hidVal  )) ||  // 사업소득거래처
             ( flag=='5'  && (strCd.getValue().trim() == scwin.ed_etcIncomeClntNo_hidVal  )) ||  // 기타소득거래처
            //  ( flag=='6'  && (strCd.getValue().trim() == scwin.txtClntCrn                 )) ||  // 사업자등록번호
             ( flag=='8'  && (strCd.getValue().trim() == scwin.ed_workSiteCd_hidVal       )) ||  // 근무지
	         ( flag=='9'  && (strCd.getValue().trim() == scwin.ed_vehclShortCd_hidVal     ))     // 차량번호 : 차량단축번호
	        ) {
		    // KYU_TEST : 히든 비교시 코드가 null 이 아니어야 함. (코드 null 일 때 명 null 처리)
		    if ( strCd.getValue() != "" ) return;
	    }

		// strNm.value="";
        strNm.setValue("");

        // KYU_ISSUE, KYU_ORDER : 2026-02-11. 장비코드 검증 - 해당함수 내에서 9 번에서 장비코드 초기화
        if ( flag == '9' ) {
            scwin.txt_eqCd = "";  // 장비코드 초기화
        }

        // 명 초기화 (한줄로 가능)
        // switch (flag){
        //     case '1'  : ed_declarDeptNm.setValue("");    break;  // 귀속부서
        //     case '2'  : ed_acctNm.setValue("");          break;  // 계정
        //     case '3'  : ed_clntNm.setValue("");          break;  // 거래처
        //     case '4'  : ed_bizIncomeClntNm.setValue(""); break;  // 사업소득거래처
        //     case '5'  : ed_etcIncomeClntNm.setValue(""); break;  // 기타소득거래처
        //     // case '6'  : ed_vehclNo.setValue("");         break;  // 사업자등록번호
        //     case '8'  : ed_workSiteNm.setValue("");      break;  // 근무지
        //     case '9'  : ed_vehclNo.setValue("");         break;  // 차량번호 : 차량번호
        //     default   : break;
        // }

//		strCd.hidVal="";

        // 히든값 초기화
        switch (flag){
			case '1'  : scwin.ed_declarDept_hidVal      = ""; break;  // 귀속부서
			case '2'  : scwin.ed_acctCd_hidVal          = ""; break;  // 계정
			case '3'  : scwin.ed_clntNo_hidVal          = ""; break;  // 거래처
			case '4'  : scwin.ed_bizIncomeClntNo_hidVal = ""; break;  // 사업소득거래처
            case '5'  : scwin.ed_etcIncomeClntNo_hidVal = ""; break;  // 기타소득거래처
            // case '6'  : scwin.txtClntCrn                = ""; break;  // 사업자등록번호
            case '8'  : scwin.ed_workSiteCd_hidVal      = ""; break;  // 근무지
            case '9'  : scwin.ed_vehclShortCd_hidVal    = ""; break;  // 차량번호
            default   : break;
        }

		// if(strCd.text.trim()!="") {
		// 	f_openPopUp(flag,'T');

		if(strCd.getValue().trim()!="") {
	        // 팝업 로딩
            scwin.f_openPopUp(flag,'T');
        }
};


