//-------------------------------------------------------------------------
// function name : f_incomeClsGubun
// function desc : 소득구분코드에 따른 변경
// function Parameter : null
//-------------------------------------------------------------------------
scwin.f_incomeClsGubun = async function()
{
    console.log("----- - f_incomeClsGubun (소득구분코드에 따른 변경) ------------------------------------");

	// 소득구분코드가 60(필요경비 없는 기타소득)인경우 필요경비 없음
    if(lc_incomeClsCd.getValue() == "60") {

		// chk_needEpenseYn.checked = false;
        cbx_needEpenseYn.checkAll(false);
        $c.gus.cfEnableObj(cbx_needEpenseYn, false);

        $c.gus.cfEnableObj(ed_etcIncomeTax, true);	// 소득세
        $c.gus.cfEnableObj(ed_etcManTax, true);	// 지방소득세

    // 소득구분코드가 62(그 밖 필요경비 있는 기타소득), 71(상금 및 부상), 72(광업권)
    // 73(지역권), 74(주택입주지체상금), 75(원고료)
    // 76(강연료) 인경우 필요경비 있음
    } else if (   lc_incomeClsCd.getValue() == "62" || lc_incomeClsCd.getValue() == "71" || lc_incomeClsCd.getValue() == "72"
       		   || lc_incomeClsCd.getValue() == "73" || lc_incomeClsCd.getValue() == "74" || lc_incomeClsCd.getValue() == "75"
       		   || lc_incomeClsCd.getValue() == "76") {

		// chk_needEpenseYn.checked = true;
        cbx_needEpenseYn.checkAll(true);
        $c.gus.cfEnableObj(cbx_needEpenseYn, false);

        $c.gus.cfEnableObj(ed_etcIncomeTax, true);	// 소득세
        $c.gus.cfEnableObj(ed_etcManTax, true);	// 지방소득세

	// 68(비과세)인경우 필요경비 / 소득세 없음
	} else if (lc_incomeClsCd.getValue() == "68") {

		// chk_needEpenseYn.checked = false;
        cbx_needEpenseYn.checkAll(false);
        $c.gus.cfEnableObj(cbx_needEpenseYn, false);

        $c.gus.cfEnableObj(ed_etcIncomeTax, false);	// 소득세
        $c.gus.cfEnableObj(ed_etcManTax, false);		// 지방소득세

	// 69(분리과세)인경우 필요경비 없음
    } else if (lc_incomeClsCd.getValue() == "69") {

		// chk_needEpenseYn.checked = false;
        cbx_needEpenseYn.checkAll(false);
        $c.gus.cfEnableObj(cbx_needEpenseYn, false);

        $c.gus.cfEnableObj(ed_etcIncomeTax, true);	// 소득세
        $c.gus.cfEnableObj(ed_etcManTax, true);	// 지방소득세

    } else {
        $c.gus.cfEnableObj(cbx_needEpenseYn, true);

        $c.gus.cfEnableObj(ed_etcIncomeTax, true);	// 소득세
        $c.gus.cfEnableObj(ed_etcManTax, true);	// 지방소득세
    }

    // KYU_NEW : 공급가액 focus out 이벤트 추가
    scwin.ed_totSal_onblur();
};

