//-------------------------------------------------------------------------
// function name : f_bizEtcGubun
// function desc : 원천세구분코드
// function Parameter : null
//-------------------------------------------------------------------------
scwin.f_bizEtcGubun = function()
{
    console.log("----- - f_bizEtcGubun (원천세구분코드)  ["+lc_withholdClsCd.getValue()+"]");

	// 사업소득
    if(lc_withholdClsCd.getValue() == scwin.sBizIncome) {  // "Z2" 사업소득
        ed_etcIncomeTax.setValue(0);
        ed_etcManTax.setValue(0);
        $c.gus.cfEnableObj(ed_etcIncomeTax, false);
        $c.gus.cfEnableObj(ed_etcManTax, false);

        if (!$c.gus.cfIsNull(ed_etcIncomeClntNo.getValue())) {
            ed_bizIncomeClntNo.setValue( ed_etcIncomeClntNo.getValue());
            ed_bizIncomeClntNm.setValue( ed_etcIncomeClntNm.getValue() );
            ed_etcIncomeClntNo.setValue("");
            ed_etcIncomeClntNm.setValue("");
		}
        // 사업소득거래처
        $c.gus.cfEnableObj(ed_bizIncomeClntNo, true);
        $c.gus.cfEnableObj(ed_bizIncomeClntNm, false);
        $c.gus.cfEnableObj(btn_bizIncomeClntNo, true);

		// 기타소득거래처
        $c.gus.cfEnableObj(ed_etcIncomeClntNo, false);
        $c.gus.cfEnableObj(ed_etcIncomeClntNm, false);
        $c.gus.cfEnableObj(btn_etcIncomeClntNo, false);

        // 소득구분코드
        lc_incomeClsCd.setSelectedIndex(-1);
        $c.gus.cfEnableObj(lc_incomeClsCd, false);
        console.log("  ==--== 비활성 (소득구분코드)");

        // 업종구분코드
        if (lc_businessClsCd.getValue() == "") {
            lc_businessClsCd.setSelectedIndex(-1);
        }

        if(lc_businessClsCd.getValue() == "851101") {  // FI084 (업종구분) 851101 병의원
            $c.gus.cfEnableObj(ed_bizIncomeCrn, true);
        } else {
            // 사업소득사업자번호
        	ed_bizIncomeCrn.setValue("");
            $c.gus.cfEnableObj(ed_bizIncomeCrn, false);   // 비활성
        }

        $c.gus.cfEnableObj(lc_businessClsCd, true);

		// chk_needEpenseYn.checked=false;
        cbx_needEpenseYn.checkAll("false");
		$c.gus.cfEnableObj(cbx_needEpenseYn, false);

		$c.gus.cfEnableObj(ed_bizIncomeFirmNm, true);

    // 기타소득
    } else if(lc_withholdClsCd.getValue() == scwin.sEtcIncome) {
        ed_bizIncomeTax.setValue(0);
        ed_bizManTax.setValue(0);
        $c.gus.cfEnableObj(ed_bizIncomeTax, false);
        $c.gus.cfEnableObj(ed_bizManTax, false);

        if (!$c.gus.cfIsNull(ed_bizIncomeClntNo.getValue())) {
            ed_etcIncomeClntNo.setValue( ed_bizIncomeClntNo.getValue() );
            ed_etcIncomeClntNm.setValue( ed_bizIncomeClntNm.getValue() );
            ed_bizIncomeClntNo.setValue( "" );
            ed_bizIncomeClntNm.setValue( "" );
        }
        // 사업소득거래처
        $c.gus.cfEnableObj(ed_bizIncomeClntNo, false);
        $c.gus.cfEnableObj(ed_bizIncomeClntNm, false);
        $c.gus.cfEnableObj(btn_bizIncomeClntNo, false);

		// 기타소득거래처
        $c.gus.cfEnableObj(ed_etcIncomeClntNo, true);
        $c.gus.cfEnableObj(ed_etcIncomeClntNm, false);
        $c.gus.cfEnableObj(btn_etcIncomeClntNo, true);

        // 소득구분코드
        if (lc_incomeClsCd.getValue() == "") {
            lc_incomeClsCd.setSelectedIndex(-1);
        }
        $c.gus.cfEnableObj(lc_incomeClsCd, true);
        console.log("  ==--== 활성 (소득구분코드)");

        // 업종구분코드
        lc_businessClsCd.setSelectedIndex(-1);

        $c.gus.cfEnableObj(lc_businessClsCd, false);
        $c.gus.cfEnableObj(cbx_needEpenseYn, true);
		$c.gus.cfEnableObj(ed_bizIncomeFirmNm, false);

    	ed_bizIncomeCrn.setValue("");
        $c.gus.cfEnableObj(ed_bizIncomeCrn, false);

    }

    // 총급여가 0이 아닐경우 구분코드 변경 시
    // if (ed_totSal.text != "0") {
    if ( parseInt(ed_totSal.getValue()) != 0) {
        // 사업소득
		if (lc_withholdClsCd.getValue() == scwin.sBizIncome)    // "Z2" 사업소득
        {
	    	var temp1 = parseInt(ed_totSal.getValue().trim()) * scwin.f_bizTaxRate();
            ed_bizIncomeTax.setValue( temp1 );
	    	var temp2 = parseInt(ed_bizIncomeTax.getValue().trim()) * 0.1;
            ed_bizManTax.setValue( temp2 );
        }
	    // 기타소득
		else if(lc_withholdClsCd.getValue() == scwin.sEtcIncome)  // "Z3" 기타소득
        {
			// 기타소득금액이 50,000원 이하이면 기타소득세 및 지방소득세를 납부하지 아니함.
			if ( parseInt(ed_totSal.getValue().trim()) > 50000 )
            {
				// if (chk_needEpenseYn.checked) {
                if (cbx_needEpenseYn.getValue() == "1") {
					var temp3 = (parseInt(ed_totSal.getValue().trim()) - (parseInt(ed_totSal.getValue().trim()) * 0.6)) * scwin.f_ectTaxRate(cbx_needEpenseYn.getValue());
                    ed_etcIncomeTax.setValue( temp3 );
				} else {
			        var temp4 = parseInt(ed_totSal.getValue().trim()) * scwin.f_ectTaxRate(cbx_needEpenseYn.getValue());
                    ed_etcIncomeTax.setValue( temp4 );
				}
				var temp5 = parseInt(ed_etcIncomeTax.getValue().trim()) * 0.1;
                ed_etcManTax.setValue( temp5 );
			} else {
				ed_etcIncomeTax.setValue(0);
				ed_etcManTax.setValue(0);
			}
		}
    }
};


//-------------------------------------------------------------------------
// function name : f_ectTaxRate
// function desc : 기타소득 세율
// function Parameter : NeedEpenseYn : 필요경비여부
//-------------------------------------------------------------------------
scwin.f_ectTaxRate = function(NeedEpenseYn)
{
    console.log("=== f_ectTaxRate (기타소득 세율)  필요경비여부 ["+NeedEpenseYn+"]");

	var nTaxRate = 0;	// 세율
	var incomeAmt = 0;	// 소득금액

    // 체크아웃이면 리턴 : 체크아웃이 0 인지 불분명  KYU_TEST
    // if (ed_totSal.text == "0") return 0;
    if ( parseInt(ed_totSal.getValue()) == 0 ) return 0;

	// 소득구분코드가 60(필요경비 없는 기타소득), 62(그 밖 필요경비 있는 기타소득), 63(연금저축,소기업소상공인공제부금해지소득)
	// 71(상금 및 부상), 72(광업권), 73(지역권)
	// 74(주택입주지체상금), 75(원고료), 76(강연료)인 경우는 세율 : 20%
	if (lc_incomeClsCd.getValue() == "60" || lc_incomeClsCd.getValue() == "62" || lc_incomeClsCd.getValue() == "63"
		|| lc_incomeClsCd.getValue() == "71" || lc_incomeClsCd.getValue() == "72" || lc_incomeClsCd.getValue() == "73"
		|| lc_incomeClsCd.getValue() == "74" || lc_incomeClsCd.getValue() == "75" || lc_incomeClsCd.getValue() == "76") {

		nTaxRate = 0.2;

	// 소득구분코드가 68(비과세)인 경우 세율 : 0%
	} else if (lc_incomeClsCd.getValue() == "68") {

		nTaxRate = 0;

	// 소득구분코드가 69(분리과세)인 경우
	}
    else if (lc_incomeClsCd.getValue() == "69")
    {
        // KYU_TEST : 체크박스 체크인 기준은?
		// if(NeedEpenseYn) {
        if ( NeedEpenseYn == "1" )
        {
			incomeAmt = (parseInt(ed_totSal.getValue().trim()) - (parseInt(ed_totSal.getValue().trim()) * 0.6));
		} else {
			incomeAmt = parseInt(ed_totSal.getValue().trim());
		}

    	// 소득금액(연간총지급총액 - 필요경비) > 3억 세율 : 30%
    	// 소득금액(연간총지급총액 - 필요경비) <= 3억 세율 : 20%
		if (Number(incomeAmt) > 300000000) {
    		nTaxRate = 0.3;
    	} else {
    		nTaxRate = 0.2;
    	}
	// 그외 : 0%
	} else {
		nTaxRate = 0;
	}

    console.log("  nTaxRate ["+nTaxRate+"]");
	return nTaxRate;
};


//-------------------------------------------------------------------------
// function name : f_bizTaxRate
// function desc : 사업소득 세율
// function Parameter : null
//-------------------------------------------------------------------------
scwin.f_bizTaxRate = function()
{
	var nTaxRate = 0;	// 세율

    if (ed_totSal.getValue() == "0") return 0;

    // 사업소득이 940905(유흥접객원)인 경우는 세율이 5%
   	if (lc_businessClsCd.getValue() == "940905") {  // FI084 (업종구분)	940905	유흥접객원

    	nTaxRate = 0.05;

   	// 선택하지 않았을 경우 0%
   	} else if (lc_businessClsCd.getValue() == "") {

    	nTaxRate = 0;

   	// 그외의 경우 3%
   	} else {

    	nTaxRate = 0.03;
   	}

	return nTaxRate;
};


