//-------------------------------------------------------------------------
// 히든값체크
//-------------------------------------------------------------------------
scwin.f_HiddenCheck = async function(str,msg){
    console.log("=== f_HiddenCheck(히든값체크)  str ["+str.getValue()+"]  msg ["+msg+"]");

    if(str.getValue().trim()=="") return true;

    // if (str.text.trim() != str.hidVal) {
    if ( ( msg=="귀속부서"       && (str.getValue().trim() != scwin.ed_declarDept_hidVal          )) ||
         ( msg=="계정"           && (str.getValue().trim() != scwin.ed_acctCd_hidVal              )) ||
         ( msg=="거래처"         && (str.getValue().trim() != scwin.ed_clntNo_hidVal              ))
       ) {
        console.log(" -- 히든값 오류 ["+str.getValue()+"] ["+scwin.ed_declarDept_hidVal+"]["+scwin.ed_acctCd_hidVal+"]["+scwin.ed_clntNo_hidVal+"]");
    	await $c.gus.cfAlertMsg($c.data.getMessage(MSG_CM_ERR_038,msg));
    	// str.SelectAll = "true";
    	str.focus();
    	return false;
    }else{
    	return true;
    }
};


