		var ju1 =ds_withhold.getCellData(i, "ssn").substring(0,6);
		var ju2 =ds_withhold.getCellData(i, "ssn").substring(6,13);

		var juminCheck = ju2.substring(0,1);

	    //주민번호 뒷자리가 5,6,7,8 인경우는 외국인이므로 주민등록형식을 체크하지 않는다.
		if(juminCheck == "5" || juminCheck == "6" || juminCheck == "7" || juminCheck == "8") {

