            ds_withhold.setRowPosition(i);
            lc_localAlienClsCd.focus();
			return false;
		}

    	// 주소
		if ($c.gus.cfIsNull(ds_withhold.getCellData(i, "addr"))) {
            await $c.win.alert(j + "번째 행의 주소을(를) 입력하십시요");
            ds_withhold.setRowPosition(i);
            ed_addr.focus();
			return false;
		}

    	// 지급수단
		if ($c.gus.cfIsNull(ds_withhold.getCellData(i, "reqPayMthdCd"))) {
