};

//-------------------------------------------------------------------------
// function name : check_jumin
// function desc : 주민번호 체크
// function Parameter : ju1 : 주민번호(년월일), ju2 : 주민번호(뒷자리)
//-------------------------------------------------------------------------
scwin.check_jumin = function(ju1, ju2) {

	//주민번호유효성검사시작
	//첫자리 유효성검사
	var yy = ju1.substring(0,2);
	var mm = ju1.substring(2,4);
	var dd = ju1.substring(4,6);
	var gender = ju2.substring(0,1);
	var ck = 0;

	if(yy < 20 || mm < 1 || mm > 12 || dd < 0 || dd > 31 || gender > 2 || gender < 1){
		return false;
	}
	//끝자리 유효성검사
	var total = ju1 + ju2;

	for(j=0;j<12;j++){
		ck += (j%8+2)*total.substring(j,j+1);
	}

	ck = (11-(ck%11))%10;
	if(parseInt(ck) != parseInt(total.substring(12,13))){
		return false;
	}

	return true;
};


