//-------------------------------------------------------------------------
scwin.sbm_cancel_submitdone = async function (e) {
    console.log("▷ sbm_cancel_submitdone (전표취소 submitdone)");

    if( e.responseJSON.resultDataSet[0].Code != 0 ) return;

// <!-- 전표삭제 DataSet -->
// language=JavaScript for=tr_cancel event=OnSuccess()>
    await $c.gus.cfAlertMsg(MSG_CM_INF_001);	// 성공적으로 저장하였습니다
    // ds_withhold.ClearData();
    ds_withhold.removeAll();

    $c.gus.cfEnableObj(ica_closeYm, true);
	$c.gus.cfEnableObj(ed_declarDept, true);
	$c.gus.cfEnableObj(ed_declarDeptNm, true);
	$c.gus.cfDisableKeyData();
    $c.gus.cfEnableAllBtn();

	scwin.f_Retrieve();
	// gr_withhold.ColumnProp('checkYn','HeadCheck')="false";
    gr_withhold.setHeaderValue("checkYn", false);  // 헤더 체크 풀기
};


