//-------------------------------------------------------------------------
// 원천징수 영수증 발행
//-------------------------------------------------------------------------
scwin.f_OzReport = async function (e) {
	var vWithholdNo = "";
	var i = 0;
	var checkedCnt = 0;

    var reportName = "";

	for ( i = 0 ; i < ds_withhold.getTotalRow() ; i++){
		if(ds_withhold.getCellData(i,"checkYn") == "T"){
		    checkedCnt += 1;
		}
	}
	if(checkedCnt == 0){
		await $c.win.alert("선택된 항목이 없습니다.");
		return;
	}
	if(checkedCnt > 1){
		await $c.win.alert("출력은 한건씩 가능합니다.");
		checkedCnt = 0;
		return;
	}

	for ( i = 0 ; i < ds_withhold.getTotalRow() ; i++){

		if(ds_withhold.getCellData(i,"checkYn") == "T"){

			vWithholdNo = ds_withhold.getCellData(i,"withholdNo");

			// 쿼리(ODI)에 적용할 파라미터를 설정(OZParam)
			//원천세 구분에 따른 출력(사업소득,기타소득)
			if(ds_withhold.getCellData(i, "withholdClsCd") =="Z2"){  //사업소득
				// var	 odiParam = new ODIParam("fi_404_01_11b_02") ;
                reportName = "fi_404_01_11b_02";
			}else{
				// var odiParam = new ODIParam("fi_404_01_11b") ;
                reportName = "fi_404_01_11b";
			}

			// odiParam.add("withholdNo",vWithholdNo.trim());
			// odiParam.add("coCd",ed_coCd.text.trim());
			// odiParam.add("coClsCd",txtCoClsCd.value.trim());

			// // 리포트(OZR)에 적용할 파라미터를 설정(OZFormParam)
			// var formParam = new FormParam() ;
			// //formParam.add("form1","폼1") ;

			// // OZ 뷰어에 대한 설정(상세 설정은 'oz report viewer guide.pdf'를 참조)
			// var viewerParam = new ViewerParam();
			// //viewerParam.add("viewer.showtree","false"); // 트리 표시
			// viewerParam.add("viewer.zoom","100");
			// viewerParam.add("viewer.useprogressbar","false");		//PROGRESSBAR 안보이게....

			// 원천세구분코드
			if ($c.gus.cfIsNull(ds_withhold.getCellData(i, "withholdClsCd"))) {
                await $c.gus.alert(i + "번째 행의 원천세구분코드을(를) 선택하십시요");
	            ds_withhold.setRowPosition(i);
	            lc_withholdClsCd.focus();
				return false;
			}

			//원천세 구분에 따른 출력(사업소득,기타소득)
			if(ds_withhold.getCellData(i, "withholdClsCd") =="Z2"){  // 사업소득
				// cfOZReport("chb_printCheck", "chb_printCheck", "/ac/fi/taxbiz/withhold/fi_404_01_11b_02.ozr", odiParam, viewerParam, formParam);

			    let data = {
			        reportName: "/ac/fi/taxbiz/withhold/fi_404_01_11b_02.ozr",
			        odiParam : {
			            //  sysPath             : "dbl.ac.fi.taxbiz.withhold"
						 withholdNo          : vWithholdNo
			            ,coCd                : ed_coCd.getValue()
						,coClsCd             : scwin.txtCoClsCd.trim()
			        },
			        viewerParam : {

			             viewer         : 100    // 배율 설정
			            ,useprogressbar : false  // 프로그레스바 쓸지 말지
			            // ,mode           : "print"  // 인쇄 옵션창 표시 없이 바로 출력
			        },
			        formParam : {

			        }
			    }

			    console.log("  사업소득 원천징수영수증 data ["+JSON.stringify(data)+"]");

                scwin.openPopup(data);
			}else{
				// cfOZReport("chb_printCheck", "chb_printCheck", "/ac/fi/taxbiz/withhold/fi_404_01_11b.ozr", odiParam, viewerParam, formParam);

			    let data = {
			        reportName: "/ac/fi/taxbiz/withhold/fi_404_01_11b.ozr",
			        odiParam : {
			            //  sysPath             : "dbl.ac.fi.taxbiz.withhold"
						 withholdNo          : vWithholdNo
			            ,coCd                : ed_coCd.getValue()
						,coClsCd             : scwin.txtCoClsCd.trim()
			        },
			        viewerParam : {

			             viewer         : 100    // 배율 설정
			            ,useprogressbar : false  // 프로그레스바 쓸지 말지
			            // ,mode           : "print"  // 인쇄 옵션창 표시 없이 바로 출력
			        },
			        formParam : {

			        }
			    }

			    console.log("  기타소득 원천징수영수증 data ["+JSON.stringify(data)+"]");

                scwin.openPopup(data);
			}
		}
	}
};

//-------------------------------------------------------------------------
//  openPopup 팝업 오픈
//-------------------------------------------------------------------------
scwin.openPopup = async function(data){
    let opts = {
        id: "ozReportPopup",
        popupName: "오즈 리포트",
        modal: true,
        type: "browserPopup",
        width: 1000,
        height: 600,
        title: "오즈 리포트"
    };
    await $c.win.openPopup("/ui/cm/zz/ozreportPopup.xml", opts, data);
};


//-------------------------------------------------------------------------
// 총금액 : 처음에 0 입력 불가
//-------------------------------------------------------------------------
scwin.ed_totSal_onkeyup = function (e) {
    scwin.chkNumber(this);
};

scwin.chkNumber = function(obj) {
    console.log("  ----- chkNumber  obj ["+obj+"]");

    let val = obj.getValue();

    // 숫자 아닌 건 제거
    val = val.replace(/[^0-9]/g, "");

    // 첫 글자가 0이면 제거
    val = val.replace(/^0+/, "");

    obj.setValue( val );
};
